#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return a * b / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        int* f = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &f[i]);
            f[i]--;
        }
        int count = 0;
        for (int d = 1; d <= D; d++) {
            int* g = (int*) malloc(N * sizeof(int));
            for (int i = 0; i < N; i++) {
                g[i] = i;
            }
            for (int j = 0; j < d; j++) {
                for (int i = 0; i < N; i++) {
                    g[i] = f[g[i]];
                }
            }
            int valid = 1;
            for (int i = 0; i < N; i++) {
                if (g[i] != i) {
                    valid = 0;
                    break;
                }
            }
            if (valid) count++;
            free(g);
        }
        printf("%d\n", count);
        free(f);
    }
    return 0;
}

