import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static int lcm(int a, int b) {
        return a * b / gcd(a, b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();
            int[] f = new int[N];
            for (int i = 0; i < N; i++) {
                f[i] = sc.nextInt() - 1;
            }
            int count = 0;
            for (int d = 1; d <= D; d++) {
                int[] g = new int[N];
                for (int i = 0; i < N; i++) {
                    g[i] = i;
                }
                for (int j = 0; j < d; j++) {
                    for (int i = 0; i < N; i++) {
                        g[i] = f[g[i]];
                    }
                }
                boolean valid = true;
                for (int i = 0; i < N; i++) {
                    if (g[i] != i) {
                        valid = false;
                        break;
                    }
                }
                if (valid) count++;
            }
            System.out.println(count);
        }
    }
}

