const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function gcd(a, b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

function lcm(a, b) {
    return a * b / gcd(a, b);
}

let T = parseInt(lines[idx++]);
while (T-- > 0) {
    let [N, D] = lines[idx++].trim().split(' ').map(Number);
    let f = lines[idx++].trim().split(' ').map(Number).map(x => x - 1);
    let count = 0;
    for (let d = 1; d <= D; d++) {
        let g = Array(N).fill(0).map((_, i) => i);
        for (let j = 0; j < d; j++) {
            g = g.map(i => f[i]);
        }
        if (g.every((x, i) => x == i)) count++;
    }
    console.log(count);
}

